import React from "react"
import Card from "./Card"
import contacts from "../Contacts"

function createCard(contact) {
    return (
      <Card
        key={contact.id}
        name={contact.name}
        tel={contact.phone}
        email={contact.email}
      />
    );
  }

function App () {
    return(
        <div>
            {contacts.map(createCard)}
        </div>
    )
}

export default App;
